import React, { useRef, useEffect, useCallback } from 'react';
import { WF_NODES, WF_EDGES } from '../data';
import './LiveWorkflow.css';

const NODE_W = 170, NODE_H = 56;
const ORB_COLORS = ['#e8571a','#a78bfa','#4ade80','#60a5fa','#fbbf24','#f472b6','#2dd4bf','#f97316'];

// Build adjacency maps
function buildAdjacency() {
  const leftOf  = {};
  const rightOf = {};
  WF_NODES.forEach(n => { leftOf[n.id] = new Set(); rightOf[n.id] = new Set(); });
  WF_EDGES.forEach(([a,b]) => { rightOf[a].add(b); leftOf[b].add(a); });
  return { leftOf, rightOf };
}
const { leftOf, rightOf } = buildAdjacency();

// Elbow-style path: straight segments with a tight corner radius
// Goes: right from exit → elbow → straight to entry
const CORNER_R = 14; // px, corner rounding radius

function edgePoints(fromId, toId) {
  const f = WF_NODES.find(n => n.id === fromId);
  const t = WF_NODES.find(n => n.id === toId);
  // Exit from right-middle of source, enter left-middle of target
  const fx = f.x + NODE_W;
  const fy = f.y + NODE_H / 2;
  const tx = t.x;
  const ty = t.y + NODE_H / 2;
  return { fx, fy, tx, ty };
}

function makePath(fromId, toId) {
  const { fx, fy, tx, ty } = edgePoints(fromId, toId);

  const sameRow = Math.abs(fy - ty) < 4;

  if (sameRow) {
    // Pure horizontal line
    return `M${fx},${fy} L${tx},${ty}`;
  }

  // Midpoint for the horizontal leg
  const midX = fx + (tx - fx) / 2;
  const r = CORNER_R;
  const dy = ty > fy ? r : -r;
  const dx = tx > midX ? r : -r;

  // Two elbows: exit right → turn down/up → go horizontal → turn → arrive left
  // Path: M fx,fy  H (midX-dx)  Q midX,fy midX,(fy+dy)  V (ty-dy)  Q midX,ty (midX+dx),ty  H tx
  const hDir1 = midX - r;
  const hDir2 = midX + r;

  return [
    `M${fx},${fy}`,
    `H${hDir1}`,
    `Q${midX},${fy} ${midX},${fy + dy}`,
    `V${ty - dy}`,
    `Q${midX},${ty} ${hDir2},${ty}`,
    `H${tx}`,
  ].join(' ');
}

// Point along the elbow path for orb travel (parametric approximation)
function bezierPt(fx, fy, tx2, ty2, t) {
  // Approximate the elbow path as a series of linear segments
  const sameRow = Math.abs(fy - ty2) < 4;
  if (sameRow) {
    return { x: fx + (tx2 - fx) * t, y: fy };
  }

  const midX = fx + (tx2 - fx) / 2;
  const r = CORNER_R;
  const dy = ty2 > fy ? r : -r;

  // Segment lengths (approximate)
  const seg1 = Math.abs(midX - r - fx);           // H to first corner start
  const seg2 = (Math.PI / 2) * r;                  // quarter-arc 1
  const seg3 = Math.abs(ty2 - fy) - 2 * r;        // vertical middle
  const seg4 = (Math.PI / 2) * r;                  // quarter-arc 2
  const seg5 = Math.abs(tx2 - (midX + r));         // H to end

  const total = seg1 + seg2 + seg3 + seg4 + seg5;
  const d = t * total;

  if (d <= seg1) {
    const p = d / seg1;
    return { x: fx + (midX - r - fx) * p, y: fy };
  }
  if (d <= seg1 + seg2) {
    const p = (d - seg1) / seg2;
    const angle = (-Math.PI / 2) + p * (Math.PI / 2) * (dy > 0 ? 1 : -1);
    return {
      x: midX - r + r * Math.cos(angle + (dy > 0 ? Math.PI / 2 : -Math.PI / 2)),
      y: fy + r * Math.sin(angle + (dy > 0 ? Math.PI / 2 : -Math.PI / 2)),
    };
  }
  if (d <= seg1 + seg2 + seg3) {
    const p = (d - seg1 - seg2) / seg3;
    return { x: midX, y: fy + dy + p * (ty2 - dy - fy - dy) };
  }
  if (d <= seg1 + seg2 + seg3 + seg4) {
    const p = (d - seg1 - seg2 - seg3) / seg4;
    const startAngle = dy > 0 ? Math.PI : 0;
    const angle = startAngle + p * (Math.PI / 2) * (dy > 0 ? 1 : -1);
    return {
      x: midX + r * Math.cos(angle - Math.PI / 2),
      y: ty2 - dy + r * Math.sin(angle - Math.PI / 2),
    };
  }
  const p = (d - seg1 - seg2 - seg3 - seg4) / seg5;
  return { x: midX + r + (tx2 - midX - r) * p, y: ty2 };
}

export default function LiveWorkflow() {
  const containerRef = useRef(null);
  const layerRef     = useRef(null);
  const svgRef       = useRef(null);
  const stateRef     = useRef({
    tx: 60, ty: -30, scale: 0.46,
    dragging: false, dragStartX: 0, dragStartY: 0, dragTx: 0, dragTy: 0,
    orbs: [],
    orbTimer: null,
    raf: null,
    hoveredId: null,
  });
  const nodeElsRef  = useRef({});
  const pathElsRef  = useRef({});

  const applyTransform = useCallback(() => {
    const s = stateRef.current;
    if (layerRef.current) {
      layerRef.current.style.transform = `translate(${s.tx}px,${s.ty}px) scale(${s.scale})`;
    }
  }, []);

  // Build DOM once
  useEffect(() => {
    const layer  = layerRef.current;
    const svg    = svgRef.current;
    if (!layer || !svg) return;

    // defs / filter
    const defs = document.createElementNS('http://www.w3.org/2000/svg','defs');
    const filter = document.createElementNS('http://www.w3.org/2000/svg','filter');
    filter.setAttribute('id','wfGlow');
    filter.innerHTML = `<feGaussianBlur stdDeviation="3" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge>`;
    defs.appendChild(filter);
    svg.appendChild(defs);

    // Edges
    WF_EDGES.forEach(([a,b]) => {
      const p = document.createElementNS('http://www.w3.org/2000/svg','path');
      p.setAttribute('fill','none');
      p.setAttribute('stroke','hsl(0,0%,45%)');
      p.setAttribute('stroke-width','2');
      p.setAttribute('opacity','0.9');
      p.setAttribute('d', makePath(a,b));
      p.style.transition = 'stroke 0.3s, opacity 0.3s';
      svg.appendChild(p);
      pathElsRef.current[`${a}-${b}`] = p;
    });

    // Nodes
    WF_NODES.forEach(n => {
      const el = document.createElement('div');
      el.className = 'wf-node-card';
      el.id = `wfn-${n.id}`;
      el.style.cssText = `
        left:${n.x}px; top:${n.y}px;
        background:${n.bg};
        border-color:${n.border};
        color:${n.color};
      `;
      el.innerHTML = `
        <span class="wf-node-emoji">${n.emoji}</span>
        <div class="wf-node-info">
          <p class="wf-node-title" style="color:${n.color}">${n.title}</p>
          <p class="wf-node-sub">${n.sub}</p>
        </div>`;

      el.addEventListener('mouseenter', () => onNodeEnter(n.id));
      el.addEventListener('mouseleave', () => onNodeLeave());

      layer.appendChild(el);
      nodeElsRef.current[n.id] = el;
    });

    applyTransform();

    // Start orb animation loop
    const animLoop = () => {
      const s = stateRef.current;
      for (let i = s.orbs.length - 1; i >= 0; i--) {
        const o = s.orbs[i];
        o.t += o.speed;
        if (o.t >= 1) {
          o.el.style.display = 'none';
          layer.removeChild(o.el);
          s.orbs.splice(i, 1);
          continue;
        }
        const pt = bezierPt(o.fx, o.fy, o.tx, o.ty, o.t);
        o.el.style.left = pt.x + 'px';
        o.el.style.top  = pt.y + 'px';
      }
      stateRef.current.raf = requestAnimationFrame(animLoop);
    };
    stateRef.current.raf = requestAnimationFrame(animLoop);

    // Schedule random orbs
    const scheduleOrb = () => {
      launchOrb();
      stateRef.current.orbTimer = setTimeout(scheduleOrb, 900 + Math.random() * 900);
    };
    scheduleOrb();

    return () => {
      cancelAnimationFrame(stateRef.current.raf);
      clearTimeout(stateRef.current.orbTimer);
    };
  }, []); // eslint-disable-line

  function launchOrb(fromId, toId) {
    const layer = layerRef.current;
    if (!layer) return;

    let edgeFromId = fromId, edgeToId = toId;
    if (!edgeFromId) {
      const edge = WF_EDGES[Math.floor(Math.random() * WF_EDGES.length)];
      [edgeFromId, edgeToId] = edge;
    }
    const { fx, fy, tx: etx, ty: ety } = edgePoints(edgeFromId, edgeToId);
    const color = ORB_COLORS[Math.floor(Math.random() * ORB_COLORS.length)];

    const orbEl = document.createElement('div');
    orbEl.className = 'wf-orb';
    orbEl.style.cssText = `
      display:block;
      background:${color};
      box-shadow:0 0 10px 3px ${color};
      transform:translate(-50%,-50%);
    `;
    layer.appendChild(orbEl);

    stateRef.current.orbs.push({
      el: orbEl, fx, fy, tx: etx, ty: ety,
      t: 0, speed: 0.007 + Math.random() * 0.007,
    });
  }

  function onNodeEnter(id) {
    stateRef.current.hoveredId = id;
    const neighbours = new Set([id, ...leftOf[id], ...rightOf[id]]);

    Object.entries(nodeElsRef.current).forEach(([nid, el]) => {
      if (neighbours.has(nid)) {
        el.classList.remove('wf-node--dimmed');
        if (nid === id) el.classList.add('wf-node--highlighted');
      } else {
        el.classList.add('wf-node--dimmed');
        el.classList.remove('wf-node--highlighted');
      }
    });

    Object.entries(pathElsRef.current).forEach(([key, p]) => {
      const [a, b] = key.split('-n').reduce((acc, v, i) => {
        if (i === 0) acc.push(v); else acc.push('n' + v); return acc;
      }, []);
      const isConnected = (a === id || b === id);
      p.setAttribute('stroke', isConnected ? 'hsl(0,0%,70%)' : 'hsl(0,0%,25%)');
      p.setAttribute('opacity', isConnected ? '1' : '0.2');
    });

    // Launch orbs on connected edges
    WF_EDGES.forEach(([a, b]) => {
      if (a === id || b === id) launchOrb(a, b);
    });
  }

  function onNodeLeave() {
    stateRef.current.hoveredId = null;
    Object.values(nodeElsRef.current).forEach(el => {
      el.classList.remove('wf-node--dimmed', 'wf-node--highlighted');
    });
    Object.values(pathElsRef.current).forEach(p => {
      p.setAttribute('stroke', 'hsl(0,0%,45%)');
      p.setAttribute('opacity', '0.9');
    });
  }

  // Pan
  const onMouseDown = useCallback((e) => {
    if (e.target.closest('.wf-zoom-btn')) return;
    const s = stateRef.current;
    s.dragging = true;
    s.dragStartX = e.clientX; s.dragStartY = e.clientY;
    s.dragTx = s.tx; s.dragTy = s.ty;
    containerRef.current.style.cursor = 'grabbing';
    e.preventDefault();
  }, []);

  useEffect(() => {
    const onMove = (e) => {
      const s = stateRef.current;
      if (!s.dragging) return;
      s.tx = s.dragTx + (e.clientX - s.dragStartX);
      s.ty = s.dragTy + (e.clientY - s.dragStartY);
      applyTransform();
    };
    const onUp = () => {
      stateRef.current.dragging = false;
      if (containerRef.current) containerRef.current.style.cursor = 'grab';
    };
    window.addEventListener('mousemove', onMove);
    window.addEventListener('mouseup', onUp);
    return () => { window.removeEventListener('mousemove', onMove); window.removeEventListener('mouseup', onUp); };
  }, [applyTransform]);

  // Wheel zoom
  const onWheel = useCallback((e) => {
    e.preventDefault();
    const s = stateRef.current;
    const rect = containerRef.current.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;
    const delta = e.deltaY > 0 ? 0.9 : 1.1;
    const newScale = Math.max(0.15, Math.min(3, s.scale * delta));
    s.tx = mx - (mx - s.tx) * (newScale / s.scale);
    s.ty = my - (my - s.ty) * (newScale / s.scale);
    s.scale = newScale;
    applyTransform();
  }, [applyTransform]);

  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    el.addEventListener('wheel', onWheel, { passive: false });
    return () => el.removeEventListener('wheel', onWheel);
  }, [onWheel]);

  const zoom = (dir) => {
    const s = stateRef.current;
    s.scale = Math.max(0.15, Math.min(3, s.scale * (dir > 0 ? 1.2 : 0.8)));
    applyTransform();
  };
  const reset = () => {
    const s = stateRef.current;
    s.tx = 60; s.ty = -30; s.scale = 0.46;
    applyTransform();
  };

  return (
    <div className="live-workflow" ref={containerRef} onMouseDown={onMouseDown}>
      {/* Grid */}
      <svg className="wf-grid" aria-hidden="true">
        <defs>
          <pattern id="wfgrid" width="30" height="30" patternUnits="userSpaceOnUse">
            <path d="M 30 0 L 0 0 0 30" fill="none" stroke="currentColor" strokeWidth="0.5"/>
          </pattern>
        </defs>
        <rect width="100%" height="100%" fill="url(#wfgrid)"/>
      </svg>

      {/* Label */}
      <div className="wf-label">
        <span>Live Workflow</span>
        <span className="wf-live-dot" aria-hidden="true"/>
      </div>

      {/* Zoom controls */}
      <div className="wf-zoom-controls" aria-label="Zoom controls">
        <button className="wf-zoom-btn" onClick={() => zoom(1)} aria-label="Zoom in">+</button>
        <button className="wf-zoom-btn" onClick={() => zoom(-1)} aria-label="Zoom out">−</button>
        <button className="wf-zoom-btn wf-zoom-btn--reset" onClick={reset} aria-label="Reset view">⟳</button>
      </div>

      {/* Canvas */}
      <div className="wf-canvas-wrap">
        <div className="wf-transform-layer" ref={layerRef}>
          <svg
            ref={svgRef}
            id="wf-edges-svg"
            width="2000"
            height="2000"
            style={{ position:'absolute', top:0, left:0, overflow:'visible', pointerEvents:'none' }}
          />
        </div>
      </div>
    </div>
  );
}
